// 递归清理 JSON Schema 中大模型不支持的字段
cleanJsonSchema = function(obj) {
  var item, key, newObj, value;
  if (!obj || typeof obj !== 'object') {
    return obj;
  }
  if (Array.isArray(obj)) {
    return (function() {
      var j, len, results;
      results = [];
      for (j = 0, len = obj.length; j < len; j++) {
        item = obj[j];
        results.push(cleanJsonSchema(item));
      }
      return results;
    })();
  }
  newObj = {};
  for (key in obj) {
    value = obj[key];
    // 剔除 Gemini 不支持的字段，比如 contains (由 Joi .has() 生成)
    // 也可以根据后续报错继续添加不支持的 key
    if (key === 'contains') {
      continue;
    }
    newObj[key] = cleanJsonSchema(value);
  }
  return newObj;
};

// 尝试从杂乱文本或 Markdown 中提取 JSON 字符串
tryExtractJSON = function(text) {
  var cleanText, jsonMatch, markdownMatch;
  if (!text) {
    throw new Error("消息内容为空，json解析失败");
  }
  // 1. 清理 BOM 和首尾空白
  cleanText = text.replace(/^\uFEFF/, '').trim();
  
  // 2. 尝试从 Markdown 代码块中提取
  markdownMatch = cleanText.match(/```json\s*([\s\S]*?)\s*```/);
  if (markdownMatch) {
    return markdownMatch[1].trim();
  }
  
  // 3. 兜底方案：贪婪匹配 { ... }
  jsonMatch = cleanText.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    return jsonMatch[0];
  }
  return cleanText;
};

