// 将工具对象数组格式化为极简文本说明
formatToolsForPrompt = (tools) => {
  if (!tools || tools.length === 0) {
    return "";
  }
  return tools.map((t) => {
    return `name:${t.name}
id:${t.id}
说明: ${t.description}
参数:
${joiToText(t.joi || t.parameters, "    ")}`.trim();
  }).join("\n\n");
};

createToolTip = (toolObj) => {
  return {
    type: "function",
    name: toolObj.name,
    id: toolObj.id,
    description: toolObj.getDoc(),
    parameters: joiToJSON(toolObj.joi()),
    joi: toolObj.joi()
  };
};

createStdToolTip = (toolObj) => {
  return {
    type: "function",
    function: {
      name: toolObj.id,
      description: toolObj.getDoc(),
      parameters: joiToJSON(toolObj.joi())
    }
  };
};

